sys_ux_client_script_include.script:
function include({imports}) {

    function nfIsDataField(field) {
        return field.isDataField !== false;
    }

    function nfIsFieldReadonly(field) {
        return field.readonly === true;
    }

    function nfValIsEmpty(field, value) {
        if (value === null || value === undefined) {
            return true;
        }
        var t = field.type || field.internalType || '';
        if (t === 'boolean' || field.internalType === 'boolean') {
            return false;
        }
        if (typeof value === 'string' && value.trim() === '') {
            return true;
        }
        return false;
    }

    function nfValidateOneField(field) {
        if (!nfIsDataField(field)) {
            return { ok: true, message: null };
        }
        if (nfIsFieldReadonly(field)) {
            return { ok: true, message: null };
        }

        var rule = field.nfValidation || null;
        if (!rule) {
            return { ok: true, message: null };
        }

        var strVal = (field.value === null || field.value === undefined || field.value === '') ? null : String(field.value);

        // Mandatory check (fail fast)
        if (strVal === null) {
            if (rule.mandatory === true) {
                return { ok: false, message: 'Field is mandatory' };
            }
            return { ok: true, message: null };
        }

        var checkLength = true;
        var typ = String(rule.type || '').toLowerCase();
        switch (typ) {
            case 'integer':
                if (!/^-?\d+$/.test(strVal)) {
                    return { ok: false, message: 'Value must be an integer' };
                }
                break;
            case 'decimal':
                if (!isFinite(Number(strVal))) {
                    return { ok: false, message: 'Value must be a number' };
                }
                break;
            case 'boolean':
                if (['true', 'false', '1', '0', 'y', 'n'].indexOf(strVal.toLowerCase()) === -1) {
                    return { ok: false, message: 'Value must be a boolean' };
                }
                return { ok: true, message: null }; // nothing else applies
            case 'date':
                if (isNaN(new Date(strVal).getTime())) {
                    return { ok: false, message: 'Value must be a valid date' };
                }
                checkLength = false;
                break;
            case 'choice':
                checkLength = false;
                break;
            default:
                // no type enforcement
                break;
        }

        // Allowed values (fail fast)
        if (Array.isArray(rule.allowedValues) && rule.allowedValues.length) {
            if (rule.allowedValues.indexOf(strVal) === -1) {
                return { ok: false, message: 'Value is not in the list of allowed values' };
            }
        }

        // Length checks (fail fast)
        if (checkLength) {
            if (strVal.length < rule.minLength) {
                return { ok: false, message: 'Value is shorter than minimum length ' + rule.minLength };
            }
            if (rule.maxLength > 0 && strVal.length > rule.maxLength) {
                return { ok: false, message: 'Value exceeds maximum length ' + rule.maxLength };
            }
        }

        // Regex (final gate)
        var rx = null;
        if (rule.regex instanceof RegExp) {
            rx = rule.regex;
        } else if (typeof rule.regex === 'string' && rule.regex.length) {
            try {
                rx = new RegExp(rule.regex);
            } catch (e1) {
                return { ok: false, message: 'Value does not match regex' };
            }
        } else if (typeof rule.regexPattern === 'string' && rule.regexPattern.length) {
            try {
                rx = new RegExp(rule.regexPattern);
            } catch (e2) {
                return { ok: false, message: 'Value does not match regex' };
            }
        }
        if (rx && !rx.test(strVal)) {
            return { ok: false, message: 'Value does not match regex' };
        }

        return { ok: true, message: null };
    }

    function nfRevalidateAllFields(fields) {
        var out = {};
        var allOk = true;
        Object.keys(fields).forEach(function (key) {
            var field = fields[key];
            var result = nfValidateOneField(field);
            if (!result.ok) {
                allOk = false;
            }
            var next = Object.assign({}, field);
            if (result.message) {
                // sn_now_record_form expects Glide-style message entries (`type`), not only `messageType`.
                next.messages = [{
                    type: 'error',
                    messageType: 'error',
                    message: result.message
                }];
                next.fieldMessage = result.message;
                next.nfValidationMessage = result.message;
            } else {
                delete next.messages;
                delete next.fieldMessage;
                delete next.nfValidationMessage;
            }
            out[key] = next;
        });
        return { fields: out, allOk: allOk };
    }

    function nfGetFieldValidationErrorText(field) {
        if (field.nfValidationMessage) {
            return field.nfValidationMessage;
        }
        if (field.messages && field.messages.length) {
            var m = field.messages[0];
            if (m && m.message) {
                return m.message;
            }
        }
        return null;
    }

    /**
     * sn_now_record_form does not always render `fields[].messages` from controller state.
     * Use the same UX events as @servicenow/now-record-form-connected (sys_ux_event export):
     *   SHOW: NOW_RECORD_FORM_SECTION_COLUMN_LAYOUT#SHOW_FIELD_MESSAGE  payload: fieldName, type, message
     *   HIDE: NOW_RECORD_FORM_SECTION_COLUMN_LAYOUT#HIDE_FIELD_MESSAGE  payload: fieldName, clearAll
     * Set emitUxfRecordFormFieldMessages false to disable. Override event strings via controller props if needed.
     */
    function nfEmitUxfRecordFormFieldMessages(api, fieldsMap) {
        if (!api || typeof api.emit !== 'function') {
            return;
        }
        const showEvt = 'sn_now_record_form.NOW_RECORD_FORM_SECTION_COLUMN_LAYOUT#SHOW_FIELD_MESSAGE';
        const hideEvt = 'sn_now_record_form.NOW_RECORD_FORM_SECTION_COLUMN_LAYOUT#HIDE_FIELD_MESSAGE';

        Object.keys(fieldsMap).forEach(function (key) {
            var f = fieldsMap[key];
            if (!nfIsDataField(f)) {
                return;
            }
            var name = f.name || key;
            var err = nfGetFieldValidationErrorText(f);
            if (err) {
                api.emit(showEvt, {
                    fieldName: name,
                    type: 'error',
                    message: err
                });
            } else {
                api.emit(hideEvt, {
                    fieldName: name,
                    clearAll: false
                });
            }
        });
    }

    return {
        nfRevalidateAllFields: nfRevalidateAllFields,
        nfEmitUxfRecordFormFieldMessages: nfEmitUxfRecordFormFieldMessages
    };
}
